import{_ as a,a as e,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as l,o as i,c as o,a2 as n}from"./chunks/framework.DnrXFDHb.js";const S=JSON.parse('{"title":"إضافة قناة S3","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/s3.md","filePath":"ar-SA/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ar-SA/upload/s3.md"};function r(p,t,h,u,b,m){return i(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="إضافة-قناة-s3" tabindex="-1">إضافة قناة S3 <a class="header-anchor" href="#إضافة-قناة-s3" aria-label="Permalink to &quot;إضافة قناة S3&quot;">​</a></h1><h2 id="متى-تكون-مناسبة؟" tabindex="-1">متى تكون مناسبة؟ <a class="header-anchor" href="#متى-تكون-مناسبة؟" aria-label="Permalink to &quot;متى تكون مناسبة؟&quot;">​</a></h2><p>استخدم قناة S3 عندما:</p><ul><li>تريد ربط أي خدمة تخزين كائنات متوافقة مع S3، مثل Cloudflare R2 أو Backblaze B2 أو MinIO أو AWS S3 أو مزود متوافق آخر.</li><li>تفضل نموذج إعداد S3 المعتاد: <code>Endpoint</code> و Access Key و Secret Key.</li><li>لا تريد استخدام قناة Cloudflare R2 binding الأصلية، أو كان مزود التخزين ليس Cloudflare R2.</li></ul><h2 id="ما-الذي-تحتاجه-قبل-البدء؟" tabindex="-1">ما الذي تحتاجه قبل البدء؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-قبل-البدء؟" aria-label="Permalink to &quot;ما الذي تحتاجه قبل البدء؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>المتطلب</th><th>الغرض</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>عنوان S3 API لخدمة تخزين الكائنات.</td></tr><tr><td>اسم Bucket</td><td>الـ bucket الذي ستُحفظ فيه الملفات.</td></tr><tr><td>Region</td><td>منطقة التخزين. في Cloudflare R2 تكون غالبًا <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>معرّف مفتاح وصول S3.</td></tr><tr><td>Secret Access Key</td><td>مفتاح وصول S3 السري.</td></tr><tr><td>CDN domain</td><td>نطاق مخصص اختياري للوصول إلى الملفات.</td></tr></tbody></table><p>مثال لاستخدام Cloudflare R2 عبر S3 API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="أين-تضيفها؟" tabindex="-1">أين تضيفها؟ <a class="header-anchor" href="#أين-تضيفها؟" aria-label="Permalink to &quot;أين تضيفها؟&quot;">​</a></h2><ol><li>افتح إعدادات النظام.</li><li>انتقل إلى إعدادات الرفع.</li><li>اضغط Add Channel في الزاوية العلوية اليمنى.</li><li>اختر <code>S3</code>.</li></ol><h2 id="شرح-الحقول" tabindex="-1">شرح الحقول <a class="header-anchor" href="#شرح-الحقول" aria-label="Permalink to &quot;شرح الحقول&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الحقل</th><th>وظيفته</th><th>مطلوب</th></tr></thead><tbody><tr><td>اسم القناة</td><td>اسم واضح لقناة S3، مثل <code>s3test</code> أو <code>R2-S3</code>.</td><td>نعم</td></tr><tr><td>Enable channel</td><td>يحدد هل تشارك القناة في اختيار قناة الرفع.</td><td>موصى به</td></tr><tr><td>Endpoint</td><td>عنوان S3 service endpoint كاملًا، مع <code>https://</code>.</td><td>نعم</td></tr><tr><td>Custom CDN domain</td><td>اختياري. عند ضبطه، تفضل روابط الملفات هذا النطاق.</td><td>لا</td></tr><tr><td>Bucket name</td><td>اسم الـ bucket، مثل <code>s3test</code> أو <code>img-r2</code>.</td><td>نعم</td></tr><tr><td>Bucket region</td><td>المنطقة. في Cloudflare R2 غالبًا <code>auto</code>.</td><td>نعم</td></tr><tr><td>Access Key ID</td><td>معرّف مفتاح وصول S3.</td><td>نعم</td></tr><tr><td>Secret Access Key</td><td>مفتاح وصول S3 السري.</td><td>نعم</td></tr><tr><td>Path-style access</td><td>مفتاح توافق. مغلق افتراضيًا. قد تحتاجه بعض خدمات MinIO أو OpenList أو S3 ذاتية الاستضافة.</td><td>لا</td></tr><tr><td>Quota limit</td><td>يحدد هل تُؤخذ سعة القناة في الاعتبار عند اختيار التخزين.</td><td>لا</td></tr><tr><td>Capacity limit</td><td>مطلوب بعد تفعيل quota limit، مثل <code>10 GB</code>.</td><td>مطلوب عند تفعيل quota limit</td></tr><tr><td>Threshold</td><td>يوقف الكتابة بعد بلوغ هذه النسبة، مثل <code>90%</code>.</td><td>مطلوب عند تفعيل quota limit</td></tr><tr><td>Remark</td><td>ملاحظاتك الخاصة للصيانة.</td><td>لا</td></tr></tbody></table><h2 id="إنشاء-مفاتيح-cloudflare-r2-s3-api" tabindex="-1">إنشاء مفاتيح Cloudflare R2 S3 API <a class="header-anchor" href="#إنشاء-مفاتيح-cloudflare-r2-s3-api" aria-label="Permalink to &quot;إنشاء مفاتيح Cloudflare R2 S3 API&quot;">​</a></h2><ol><li>افتح Cloudflare Dashboard.</li><li>انتقل إلى <code>R2 Object Storage</code>.</li><li>ابحث عن <code>Manage R2 API Tokens</code> أو مدخل إدارة API token.</li></ol><p>![مدخل R2 API token](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>أنشئ R2 API token يستطيع الوصول إلى الـ bucket الهدف.</li></ol><p><img src="`+a+'" alt="إنشاء account API token" loading="lazy"></p><ol start="5"><li>انسخ قيم <code>Access Key ID</code> و <code>Secret Access Key</code>.</li></ol><p><img src="'+e+'" alt="نسخ قيم الرمز" loading="lazy"></p><ol start="6"><li>ارجع إلى صفحة R2 bucket وتأكد من اسم الـ bucket.</li><li>سجّل S3 API endpoint الخاص بالحساب. غالبًا يكون بالشكل:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><ol><li>افتح إعدادات الرفع.</li><li>اضغط Add Channel.</li><li>اختر <code>S3</code>.</li><li>أدخل اسم قناة واضحًا، مثل <code>s3test</code>.</li><li>أدخل S3 API endpoint في <code>Endpoint</code>.</li><li>إذا كنت تستخدم CDN مخصصًا فأدخله في <code>Custom CDN domain</code>، وإلا اتركه فارغًا.</li><li>أدخل اسم الـ bucket.</li><li>أدخل المنطقة. في مثال Cloudflare R2 استخدم <code>auto</code>.</li><li>أدخل Access Key ID و Secret Access Key.</li><li>اترك path-style access مغلقًا ما لم يطلبه المزود صراحة.</li><li>إذا أردت التحكم في السعة، فعّل quota limit وأدخل capacity limit و threshold.</li><li>اضغط Save.</li></ol><p><img src="'+d+'" alt="إضافة إعداد S3" loading="lazy"></p><h2 id="كيف-تتحقق؟" tabindex="-1">كيف تتحقق؟ <a class="header-anchor" href="#كيف-تتحقق؟" aria-label="Permalink to &quot;كيف تتحقق؟&quot;">​</a></h2><table tabindex="0"><thead><tr><th>الفحص</th><th>طريقة التحقق</th></tr></thead><tbody><tr><td>ظهور بطاقة القناة</td><td>بعد الحفظ يجب أن تظهر بطاقة قناة S3 في إعدادات الرفع.</td></tr><tr><td>القناة مفعلة</td><td>يجب أن يبقى المفتاح في أعلى يمين البطاقة مفعّلًا.</td></tr><tr><td>الحقول الأساسية محفوظة</td><td>يجب أن تظهر في التفاصيل قيم Endpoint و Bucket و Region و path-style access والحقول المرتبطة.</td></tr><tr><td>نجاح الرفع</td><td>ارفع صورة تجريبية وتأكد من ظهور الكائن في الـ bucket الهدف.</td></tr><tr><td>فتح الرابط</td><td>يجب أن يفتح رابط الصورة الناتج بعد الرفع بشكل طبيعي.</td></tr><tr><td>عرض السعة يعمل</td><td>إذا كان quota limit مفعّلًا، يجب أن تعرض البطاقة السعة المستخدمة والحد المضبوط.</td></tr></tbody></table><p>إحصاءات سعة S3 تُحسب من سجلات الملفات المحلية في ImgBed، وليس من استعلام مباشر للـ bucket لدى المزود في الوقت الحقيقي. بعد حفظ إعداد S3، يعيد النظام حساب دفتر الحصة من سجلات D1 الحالية.</p><p><img src="'+s+`" alt="نجاح استعلام الحصة" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="هل-أفعّل-path-style-access؟" tabindex="-1">هل أفعّل path-style access؟ <a class="header-anchor" href="#هل-أفعّل-path-style-access؟" aria-label="Permalink to &quot;هل أفعّل path-style access؟&quot;">​</a></h3><p>غالبًا لا.</p><p>فعّله فقط إذا كان مزود S3 المتوافق لا يدعم virtual-hosted-style URLs، أو إذا طلبت وثائق المزود path-style access صراحة. قد تحتاجه بعض نقاط MinIO أو S3 ذاتية الاستضافة أو OpenList.</p><h3 id="ما-فائدة-cdn-domain؟" tabindex="-1">ما فائدة CDN domain؟ <a class="header-anchor" href="#ما-فائدة-cdn-domain؟" aria-label="Permalink to &quot;ما فائدة CDN domain؟&quot;">​</a></h3><p>إذا وضعت CDN أو نطاق وصول مخصصًا أمام الـ bucket، أدخله هنا.</p><p>بعد ضبطه ستفضل روابط الملفات الناتجة هذا النطاق. إذا لم تستخدم CDN، اتركه فارغًا.</p><h3 id="لماذا-يفشل-الرفع؟" tabindex="-1">لماذا يفشل الرفع؟ <a class="header-anchor" href="#لماذا-يفشل-الرفع؟" aria-label="Permalink to &quot;لماذا يفشل الرفع؟&quot;">​</a></h3><p>تحقق أولًا من التالي:</p><ol><li>يحتوي Endpoint على عنوان <code>https://</code> كامل.</li><li>اسم الـ bucket صحيح.</li><li>Region يطابق متطلبات المزود.</li><li>تم نسخ Access Key ID و Secret Access Key بالكامل.</li><li>المفتاح يملك صلاحية الكتابة على الـ bucket الهدف.</li><li>المزود لا يتطلب path-style access، أو تم تفعيله إذا كان مطلوبًا.</li></ol><h2 id="قائمة-تحقق-سريعة" tabindex="-1">قائمة تحقق سريعة <a class="header-anchor" href="#قائمة-تحقق-سريعة" aria-label="Permalink to &quot;قائمة تحقق سريعة&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>جهّز S3 Endpoint و Bucket و Region و Access Key و Secret Key</span></span>
<span class="line"><span>-&gt; افتح إعدادات الرفع</span></span>
<span class="line"><span>-&gt; أضف قناة</span></span>
<span class="line"><span>-&gt; اختر S3</span></span>
<span class="line"><span>-&gt; أدخل Endpoint / Bucket / Region / Access Key / Secret Key</span></span>
<span class="line"><span>-&gt; أدخل CDN domain عند الحاجة</span></span>
<span class="line"><span>-&gt; اترك path-style access مغلقًا افتراضيًا</span></span>
<span class="line"><span>-&gt; فعّل quota limit عند الحاجة</span></span>
<span class="line"><span>-&gt; احفظ</span></span>
<span class="line"><span>-&gt; ارفع صورة تجريبية وتحقق من النتيجة</span></span></code></pre></div>`,40)])])}const y=l(c,[["render",r]]);export{S as __pageData,y as default};
